import{_ as t,c as o,o as a,a1 as s}from"./chunks/framework.DDNAyvCW.js";const i="/assets/aichat.DzFmaWbj.png",m=JSON.parse('{"title":"AI Dialog","description":"","frontmatter":{},"headers":[],"relativePath":"docs/ai/dialogs/index.md","filePath":"docs/ai/dialogs/index.md"}'),n={name:"docs/ai/dialogs/index.md"};function r(d,e,l,c,h,p){return a(),o("div",null,e[0]||(e[0]=[s('<h1 id="ai-dialog" tabindex="-1">AI Dialog <a class="header-anchor" href="#ai-dialog" aria-label="Permalink to &quot;AI Dialog&quot;">​</a></h1><p>The AI Dialog panel is your central hub for interacting with AI — generate commands, plan complex tasks, and automate multi-host operations.</p><p><img src="'+i+'" alt=""></p><h2 id="three-modes-for-every-workflow" tabindex="-1">Three Modes for Every Workflow <a class="header-anchor" href="#three-modes-for-every-workflow" aria-label="Permalink to &quot;Three Modes for Every Workflow&quot;">​</a></h2><p>Chaterm offers two distinct dialog modes, each designed for a different level of AI involvement. Choose the one that fits your task.</p><h3 id="command-mode" tabindex="-1">Command Mode <a class="header-anchor" href="#command-mode" aria-label="Permalink to &quot;Command Mode&quot;">​</a></h3><p><strong>AI generates commands for the active terminal — you approve before execution.</strong></p><p>In Command mode, the AI analyzes your request and produces one or more terminal commands. Each command is displayed for your review. You can approve, edit, or reject it before anything runs.</p><p><strong>Example conversation:</strong></p><blockquote><p><strong>You:</strong> Find all log files larger than 100MB in /var/log and compress them.</p><p><strong>AI:</strong> Here is a command to find and compress those files:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;*.log&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -size</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +100M</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -exec</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gzip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> {}</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\;</span></span></code></pre></div><p><strong>[Approve]</strong> <strong>[Reject]</strong></p></blockquote><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>In Command mode, commands run in your <strong>currently active terminal</strong>. Always verify you are connected to the correct host before approving.</p></div><hr><h3 id="agent-mode" tabindex="-1">Agent Mode <a class="header-anchor" href="#agent-mode" aria-label="Permalink to &quot;Agent Mode&quot;">​</a></h3><p><strong>AI autonomously executes multi-step tasks across one or more hosts.</strong></p><p>Agent mode gives the AI the ability to plan, execute, observe results, and adapt. It can operate across multiple hosts by using the <code>@</code> mention syntax. The AI continues working until the task is complete or it needs your input.</p><p><strong>Example conversation:</strong></p><blockquote><p><strong>You:</strong> @web-server-01 @web-server-02 Check disk usage on both hosts. If any partition is above 80%, find and list the top 10 largest files.</p><p><strong>AI:</strong> Starting task on 2 hosts...</p><p><em>[Executes <code>df -h</code> on web-server-01]</em> — All partitions below 80%. No action needed.</p><p><em>[Executes <code>df -h</code> on web-server-02]</em> — <code>/data</code> is at 87%.</p><p><em>[Executes <code>du -ah /data | sort -rh | head -10</code> on web-server-02]</em> — Here are the top 10 largest files...</p></blockquote><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>In Agent mode, type <code>@</code> in the input box to see a list of available hosts. You can select multiple hosts for cross-server operations.</p></div><hr><h2 id="uploading-files-and-images" tabindex="-1">Uploading Files and Images <a class="header-anchor" href="#uploading-files-and-images" aria-label="Permalink to &quot;Uploading Files and Images&quot;">​</a></h2><p>You can attach files and images to any message to give the AI additional context.</p><table tabindex="0"><thead><tr><th>Type</th><th>Supported Formats</th><th>Max Size</th><th>How to Attach</th></tr></thead><tbody><tr><td><strong>Images</strong></td><td><code>.png</code>, <code>.jpg</code>, <code>.jpeg</code>, <code>.webp</code></td><td>5 MB</td><td>Drag and drop into the input box, or click the upload button</td></tr><tr><td><strong>Text/Code files</strong></td><td><code>.txt</code>, <code>.md</code>, <code>.js</code>, <code>.ts</code>, <code>.py</code>, <code>.java</code>, <code>.cpp</code>, <code>.c</code>, <code>.html</code>, <code>.css</code>, <code>.json</code>, <code>.xml</code>, <code>.yaml</code>, <code>.yml</code>, <code>.sql</code>, <code>.sh</code>, <code>.bat</code>, <code>.ps1</code>, <code>.log</code>, <code>.csv</code>, <code>.tsv</code></td><td>1 MB</td><td>Drag and drop into the input box, or click the upload button</td></tr></tbody></table><p>Code files are automatically wrapped in syntax-highlighted code blocks based on their extension.</p><hr><h2 id="history-management" tabindex="-1">History Management <a class="header-anchor" href="#history-management" aria-label="Permalink to &quot;History Management&quot;">​</a></h2><p>Every conversation is saved automatically. You can revisit, search, and organize past dialogs.</p><h3 id="viewing-and-restoring-history" tabindex="-1">Viewing and restoring history <a class="header-anchor" href="#viewing-and-restoring-history" aria-label="Permalink to &quot;Viewing and restoring history&quot;">​</a></h3><ol><li>Click the <strong>menu button</strong> in the top-left corner of the AI dialog panel.</li><li>Browse or <strong>search</strong> history by title using the search field.</li><li>Click any history entry to <strong>restore</strong> that conversation.</li></ol><h3 id="organizing-history" tabindex="-1">Organizing history <a class="header-anchor" href="#organizing-history" aria-label="Permalink to &quot;Organizing history&quot;">​</a></h3><ul><li><strong>Favorite</strong> a conversation by clicking the star icon — favorites appear at the top of the list.</li><li><strong>Rename</strong> a conversation by clicking its title and typing a new name.</li><li><strong>Delete</strong> a conversation by clicking the delete icon on the history entry.</li></ul><p>History supports <strong>pagination</strong>, so even large numbers of past conversations remain easy to navigate.</p><hr><h2 id="layout-switching" tabindex="-1">Layout Switching <a class="header-anchor" href="#layout-switching" aria-label="Permalink to &quot;Layout Switching&quot;">​</a></h2><p>Chaterm offers two interface layouts so you can put the focus where you need it.</p><table tabindex="0"><thead><tr><th>Layout</th><th>Description</th><th>Best for</th></tr></thead><tbody><tr><td><strong>Terminal layout</strong></td><td>Terminal occupies the main area; AI sidebar is a secondary panel</td><td>Terminal-centric workflows where AI assists</td></tr><tr><td><strong>Agents layout</strong></td><td>AI conversation occupies the main area; terminal is a secondary panel</td><td>AI-driven workflows where the terminal executes</td></tr></tbody></table><p><strong>Switch layouts instantly</strong> with the keyboard shortcut:</p><ul><li><strong>macOS:</strong> <code>Cmd + E</code></li><li><strong>Windows / Linux:</strong> <code>Ctrl + E</code></li></ul><p>You can also change the layout in <a href="/docs/settings/general/">General Settings</a>. The change takes effect immediately — no restart required.</p><hr><h2 id="related-documentation" tabindex="-1">Related Documentation <a class="header-anchor" href="#related-documentation" aria-label="Permalink to &quot;Related Documentation&quot;">​</a></h2><ul><li><a href="/docs/ai/settings/">AI Settings</a> — Configure providers, models, and create new dialogs</li><li><a href="/docs/ai/preferences/">AI Preferences</a> — Fine-tune reasoning depth, auto-execution, and security policies</li><li><a href="/docs/ai/llms/">Model Configuration</a> — Add and manage AI model providers</li></ul>',41)]))}const u=t(n,[["render",r]]);export{m as __pageData,u as default};
